const raw = $input.first().json;
const incoming = raw.body || raw;
const config = {
  SUPABASE_URL: 'YOUR_SUPABASE_URL',
  SUPABASE_SERVICE_KEY: 'YOUR_SUPABASE_SERVICE_KEY',
  ANTHROPIC_API_KEY: 'YOUR_ANTHROPIC_API_KEY',
  GRYNOW_WEBSITE_ID: 'YOUR_GRYNOW_WEBSITE_ID',
  MYWALL_WEBSITE_ID: 'YOUR_MYWALL_WEBSITE_ID',
};
return [{ json: { ...config, ...incoming } }];

const fetch=(u,o={})=>new Promise((res,rej)=>{const iH=u.startsWith('https');const lib=require(iH?'https':'http');const m=u.match(/^https?:\/\/([^/:]+)(?::(\d+))?(\/[^?#]*)?(\?[^#]*)?/);if(!m)return rej(new Error('Bad URL: '+u));const body=o.body||null;const req=lib.request({hostname:m[1],port:m[2]?+m[2]:(iH?443:80),path:(m[3]||'/')+(m[4]||''),method:o.method||'GET',headers:{...(o.headers||{}),...(body?{'Content-Length':Buffer.byteLength(body)}:{})}},r=>{let d='';r.on('data',c=>d+=c);r.on('end',()=>res({ok:r.statusCode<300,status:r.statusCode,json:()=>Promise.resolve(JSON.parse(d||'null')),text:()=>Promise.resolve(d)}));});req.on('error',rej);if(body)req.write(body);req.end();});

const cfg = $('Config').first().json;
const sbUrl = cfg.SUPABASE_URL;
const sbKey = cfg.SUPABASE_SERVICE_KEY;
const sbH = { apikey: sbKey, Authorization: 'Bearer '+sbKey, 'Content-Type': 'application/json' };

// Fetch content version
const r = await fetch(`${sbUrl}/rest/v1/content_versions?select=*,content_requests(*)&id=eq.${cfg.content_version_id}`, { headers: { apikey: sbKey, Authorization: 'Bearer '+sbKey } });
const rows = await r.json();
const ver = rows[0] || {};
const req = ver.content_requests || {};

// Extract patterns with Claude Haiku
const haiku = await fetch('https://api.anthropic.com/v1/messages', {
  method: 'POST',
  headers: { 'x-api-key': cfg.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'Content-Type': 'application/json' },
  body: JSON.stringify({
    model: 'claude-haiku-4-5-20251001', max_tokens: 1024,
    system: 'Extract 3-5 specific, reusable positive writing patterns from approved content. Return ONLY a JSON array.',
    messages: [{ role: 'user', content: `Content type: ${req.content_type}\nPlacement: ${req.placement}\nTopic: ${req.topic}\n\nContent (first 2500 chars):\n${(ver.content_markdown||'').substring(0,2500)}\n\nReturn JSON array: [{"pattern_type":"positive","category":"tone|structure|keywords|formatting|cta","pattern":"specific actionable observation","source":"approved_content","applies_to_placement":"${req.placement}","applies_to_content_type":"${req.content_type}"}]` }]
  })
}).then(r=>r.json());

const text = haiku.content[0].text;
let patterns = [];
try {
  const m = text.match(/```json\s*([\s\S]*?)```/) || text.match(/(\[[\s\S]*\])/);
  patterns = JSON.parse(m ? m[1] : text);
  if (!Array.isArray(patterns)) patterns = [patterns];
} catch(e) { patterns = []; }

// Save patterns
if (patterns.length) {
  await fetch(`${sbUrl}/rest/v1/memory_patterns`, {
    method: 'POST', headers: sbH,
    body: JSON.stringify(patterns.map(p => ({ ...p, website_id: req.website_id, frequency: 1 })))
  });
}

// Archive content
await fetch(`${sbUrl}/rest/v1/content_archive`, {
  method: 'POST', headers: sbH,
  body: JSON.stringify({ content_version_id: cfg.content_version_id, request_id: req.id, website_id: req.website_id, placement: req.placement, content_type: req.content_type, topic: req.topic, keywords: req.keywords, word_count: ver.word_count, content_excerpt: (ver.content_markdown||'').substring(0,500), full_content: ver.content_markdown })
});

// Mark approved
await fetch(`${sbUrl}/rest/v1/content_requests?id=eq.${req.id}`, {
  method: 'PATCH', headers: sbH, body: JSON.stringify({ status: 'approved' })
});
await fetch(`${sbUrl}/rest/v1/content_versions?id=eq.${cfg.content_version_id}`, {
  method: 'PATCH', headers: sbH, body: JSON.stringify({ status: 'approved' })
});

return [{ json: { done: true, patterns_saved: patterns.length, type: 'approve' } }];

